/* =========================================
   auth.js — Supabase Authentication
   =========================================
   ⚠️  แก้ค่า SUPABASE_URL และ SUPABASE_ANON_KEY
       ให้ตรงกับโปรเจกต์ของคุณก่อนใช้งาน
       (Supabase Dashboard → Settings → API)
   ========================================= */

const SUPABASE_URL  = 'https://YOUR_PROJECT.supabase.co';  // ← เปลี่ยนตรงนี้
const SUPABASE_ANON = 'YOUR_ANON_KEY';                      // ← เปลี่ยนตรงนี้

const _sb = supabase.createClient(SUPABASE_URL, SUPABASE_ANON);

/* =========================================
   STATE
   ========================================= */
let currentUser = null;

/* ฟัง session เปลี่ยน (login / logout / refresh) */
_sb.auth.onAuthStateChange((event, session) => {
  currentUser = session?.user ?? null;
  _updateAuthUI();

  /* ยังไม่ login → เด้ง modal ทันที (ยกเว้นหน้า admin) */
  if (!currentUser && window.location.hash !== '#admin') {
    openLogin();
  }
});

/* =========================================
   OPEN / CLOSE MODAL
   ========================================= */
function openLogin() {
  document.getElementById('login-overlay').classList.add('show');
  switchLoginTab('login');
}

function closeLogin() {
  if (!currentUser) return; /* บังคับ login ก่อนปิด */
  document.getElementById('login-overlay').classList.remove('show');
}

/* =========================================
   SWITCH TAB  login ↔ register
   ========================================= */
function switchLoginTab(tab) {
  const isLogin = tab === 'login';
  document.getElementById('lf-login').style.display    = isLogin ? '' : 'none';
  document.getElementById('lf-register').style.display = isLogin ? 'none' : '';
  document.getElementById('lt-login').classList.toggle('act', isLogin);
  document.getElementById('lt-register').classList.toggle('act', !isLogin);
  document.getElementById('login-err').textContent = '';
  document.getElementById('reg-err').textContent   = '';
}

/* =========================================
   LOGIN
   ========================================= */
async function doLogin() {
  const username = document.getElementById('login-username').value.trim();
  const password = document.getElementById('login-password').value;
  const errEl    = document.getElementById('login-err');
  errEl.textContent = '';

  if (!username || !password) {
    errEl.textContent = 'กรุณากรอก Username และ Password';
    return;
  }

  /* Supabase ใช้ email — แปลง username → fake email */
  const email = username.toLowerCase() + '@drinkordoom.local';

  const btn = document.getElementById('btn-do-login');
  btn.disabled = true;
  btn.innerHTML = '<i class="fi fi-sr-spinner fi-spin"></i> กำลังเข้าสู่ระบบ...';

  const { error } = await _sb.auth.signInWithPassword({ email, password });

  btn.disabled = false;
  btn.innerHTML = '<i class="fi fi-sr-sign-in-alt"></i> เข้าสู่ระบบ';

  if (error) {
    errEl.textContent = error.message.includes('Invalid')
      ? 'Username หรือ Password ไม่ถูกต้อง'
      : error.message;
    return;
  }

  toast('ยินดีต้อนรับกลับมา! 🎉', 'success');
  closeLogin();
}

/* =========================================
   REGISTER
   ========================================= */
async function doRegister() {
  const username = document.getElementById('reg-username').value.trim();
  const password = document.getElementById('reg-password').value;
  const confirm  = document.getElementById('reg-confirm').value;
  const errEl    = document.getElementById('reg-err');
  errEl.textContent = '';

  if (!username || !password || !confirm) {
    errEl.textContent = 'กรุณากรอกข้อมูลให้ครบ';
    return;
  }
  if (username.length < 3) {
    errEl.textContent = 'Username ต้องมีอย่างน้อย 3 ตัวอักษร';
    return;
  }
  if (password.length < 6) {
    errEl.textContent = 'Password ต้องมีอย่างน้อย 6 ตัวอักษร';
    return;
  }
  if (password !== confirm) {
    errEl.textContent = 'Password ไม่ตรงกัน';
    return;
  }

  const email = username.toLowerCase() + '@drinkordoom.local';

  const btn = document.getElementById('btn-do-register');
  btn.disabled = true;
  btn.innerHTML = '<i class="fi fi-sr-spinner fi-spin"></i> กำลังสมัคร...';

  const { error } = await _sb.auth.signUp({
    email,
    password,
    options: { data: { username } }
  });

  btn.disabled = false;
  btn.innerHTML = '<i class="fi fi-sr-user-add"></i> สมัครสมาชิก';

  if (error) {
    errEl.textContent = error.message.includes('already registered')
      ? 'Username นี้ถูกใช้งานแล้ว'
      : error.message;
    return;
  }

  toast('สมัครสมาชิกสำเร็จ! ยินดีต้อนรับ 🎉', 'success');
  closeLogin();
}

/* =========================================
   LOGOUT
   ========================================= */
async function logout() {
  await _sb.auth.signOut();
  currentUser = null;
  _updateAuthUI();
  toast('ออกจากระบบแล้ว', 'info');
  openLogin();
}

/* =========================================
   UPDATE UI ตาม auth state
   ========================================= */
function _updateAuthUI() {
  const btnLogin  = document.getElementById('btn-login');
  const userChip  = document.getElementById('user-chip');
  const userLabel = document.getElementById('user-display-name');

  if (currentUser) {
    const name = currentUser.user_metadata?.username
      || currentUser.email?.split('@')[0]
      || 'user';
    if (btnLogin)  btnLogin.style.display = 'none';
    if (userChip)  userChip.style.display = 'flex';
    if (userLabel) userLabel.textContent  = name;
  } else {
    if (btnLogin)  btnLogin.style.display = 'flex';
    if (userChip)  userChip.style.display = 'none';
  }
}

/* =========================================
   CLOSE ON BACKDROP CLICK
   ========================================= */
document.getElementById('login-overlay')?.addEventListener('click', function(e) {
  if (e.target === this) closeLogin();
});

/* =========================================
   ENTER KEY SUPPORT
   ========================================= */
document.addEventListener('keydown', function(e) {
  if (e.key !== 'Enter') return;
  const overlay = document.getElementById('login-overlay');
  if (!overlay?.classList.contains('show')) return;
  const loginVisible = document.getElementById('lf-login').style.display !== 'none';
  if (loginVisible) doLogin();
  else doRegister();
});
